raw_sql:
SELECT
  ROUND(
    REGR_SLOPE(
      EXTRACT(EPOCH FROM (processed_date - opened_at)) / 86400.0,
      amount
    )::numeric, 6
  ) AS days_per_dollar,
  ROUND(REGR_INTERCEPT(
      EXTRACT(EPOCH FROM (processed_date - opened_at)) / 86400.0,
      amount
    )::numeric, 3
  ) AS intercept_days,
  ROUND(REGR_R2(
      EXTRACT(EPOCH FROM (processed_date - opened_at)) / 86400.0,
      amount
    )::numeric, 4
  ) AS r_squared,
  COUNT(*) AS n,
  ROUND((REGR_SLOPE(
      EXTRACT(EPOCH FROM (processed_date - opened_at)) / 86400.0, amount
    ) * 500)::numeric, 2) AS days_per_500_dollars
FROM flag_22
WHERE processed_date IS NOT NULL AND opened_at IS NOT NULL;

